int main()
{
    int n, a[20], b[20], cnt = 0;
    scanf("%d", &n);
    for(int i = 0; i < n; i++)
    {
        scanf("%d", &a[i]);
        if(a[i] % 2 == 0) // 如果a[i]是偶数，存入b数组
        {
            b[cnt] = a[i];
            cnt++; // 计数器加1
        }
    }
    if(cnt == 0)
    {
        printf("None\n"); // 没有偶数，输出None
    }
    else
    {
        for(int i = 0; i < cnt; i++)
        {
            printf("%d ", b[i]); // 顺次输出b数组中的元素
        }
    }
    return 0;
}

int binary_search(int a[], int n, int k)
{
    int left = 0, right = n - 1;
    while(left <= right)
    {
        int mid = (left + right) / 2;
        if(a[mid] == k)
        {
            return mid; // 找到了，返回下标
        }
        else if(a[mid] < k)
        {
            left = mid + 1; // k在mid的右边，调整左边界
        }
        else
        {
            right = mid - 1; // k在mid的左边，调整右边界
        }
    }
    return -1; // 没有找到，返回-1
}

