int main()
{
    int n, a[13][13];
    scanf("%d", &n);
    // 初始化第一列和对角线为1
    for(int i = 0; i < n; i++)
    {
        a[i][0] = a[i][i] = 1;
    }
    // 计算其余元素
    for(int i = 2; i < n; i++)
    {
        for(int j = 1; j < i; j++)
        {
            a[i][j] = a[i-1][j-1] + a[i-1][j];
        }
    }
    // 打印杨辉三角
    for(int i = 0; i < n; i++)
    {
        for(int j = 0; j <= i; j++)
        {
            printf("%6d", a[i][j]);
        }
        printf("\n");
    }
    return 0;
}

#include <stdio.h>

void twodim2onedim(int s[][10], int n, int m, int t[])
{
    int cnt = 0; // 一维数组的计数器
    for(int i = 0; i < n; i++)
    {
        for(int j = 0; j < m; j++)
        {
            t[cnt] = s[i][j]; // 将二维数组中的元素存放到一维数组中
            cnt++; // 计数器加1
        }
    }
}

int main()
{
