int triu(int x[][40], int n)
{
    for(int i = 1; i < n; i++)
    {
        for(int j = 0; j < i; j++)
        {
            if(x[i][j] != 0) // 如果左下角有非零元素，不是上三角矩阵
            {
                return 0;
            }
        }
    }
    return 1;
}

int main()
{
    int n, x[40][40];
    scanf("%d", &n);
    for(int i = 0; i < n; i++)
    {
        for(int j = 0; j < n; j++)
        {
            scanf("%d", &x[i][j]);
        }
    }
    int ans = triu(x, n);
    if(ans)
    {
        printf("YES\n");
    }
    else
    {
        printf("NO\n");
    }
    return 0;
}

#include <stdio.h>

int Symmetric_Matrix(int x[][40], int n)
{
    for(int i = 0; i < n; i++)
    {
        for(int j = i; j < n; j++) // 因为是对称矩阵，只需要判断右上角是否与左下角对称即可
        {
            if(x[i][j] != x[j][i])
            {
                return 0; // 不是对称矩阵，返回0
            }
        }
    }
    return 1; // 是对称矩阵，返回1
}

