int main()
{
    char s[81];
    scanf("%s", s);
    int cnt = 0; // 计数器，记录数字字符出现的次数
    for(int i = 0; i < strlen(s); i++)
    {
        if(s[i] >= '0' && s[i] <= '9') // 如果是数字字符，计数器加1
        {
            cnt++;
        }
    }
    printf("%d\n", cnt);
    return 0;
}

int main()
{
    char s[81];
    scanf("%s", s);
    for(int i = 0; i < strlen(s); i++)
    {
        if(s[i] >= 'a' && s[i] <= 'z') // 如果是小写字母，转换为大写字母
        {
            s[i] -= 'a' - 'A';
        }
    }
    printf("%s\n", s);
    return 0;
}

int main()
{
    char s1[81], s2[81], s3[81];
    scanf("%s%s%s", s1, s2, s3);
    char *max_str = s1; // 定义一个指向最大字符串的指针，初始指向第一个字符串
    if(strcmp(max_str, s2) < 0) // 如果第二个字符串更大，更新最大字符串指针
    {
        max_str = s2;
    }
    if(strcmp(max_str, s3) < 0) // 如果第三个字符串更大，更新最大字符串指针
    {
        max_str = s3;
    }
    printf("%s\n", max_str);
    return 0;
}

#include <stdio.h>
#include <string.h>

void del_char(char str[], char ch)
{
    int len = strlen(str);
    int cnt = 0; // 记录要删去的字符个数
    for(int i = 0; i < len; i++)
    {
        if(str[i] == ch) // 如果当前字符是指定字符，计数器加1
        {
            cnt++;
        }
        else // 否则，将当前字符向左移cnt个位置
        {
            str[i-cnt] = str[i];
        }
    }
    str[len-cnt] = '\0'; // 最后将字符串截短
}

int main()
{
    char str[81], ch;
    scanf("%s %c", str, &ch);
    del_char(str, ch);
    printf("%s\n", str);
    return 0;
}
